+
+// ============================================================================
+// Interaction Performance Tests
+// ============================================================================
+
+test.describe("Performance: Interactions", () => {
+  test("Search modal opens quickly", async ({ page }) => {
+    await page.goto("/corpus", { waitUntil: "networkidle" });
